5	namespace VeloCMS\Core;
6	
7	abstract class Module
8	{
9	    protected object $router;
10	    protected AdminMenu $admin;
11	
12	    public function __construct()
13	    {
14	        $this->admin  = new AdminMenu();
15	        $this->router = new class {
16	            public function get(string $path, string $handler): void
17	            {
18	                Router::get($path, $handler);
19	            }
20	
21	            public function post(string $path, string $handler): void
22	            {
23	                Router::post($path, $handler);
24	            }
25	        };
26	    }
27	
28	    abstract public function boot(): void;
29	
30	    public function install(): void {}
31	
32	    protected function runMigrations(string $path): void
33	    {
34	        if (!is_dir($path)) {
35	            return;
36	        }
37	
38	        $db    = Database::getInstance()->getPdo();
39	        $files = glob($path . '/*.php');
40	
41	        if ($files === false) {
42	            return;
43	        }
44	
45	        sort($files);
46	
47	        foreach ($files as $file) {
48	            require_once $file;
49	
50	            $basename  = pathinfo($file, PATHINFO_FILENAME);
51	            $className = preg_replace('/^\d+_/', '', $basename);
52	            $className = str_replace('_', '', ucwords($className, '_'));
53	
54	            if (class_exists($className)) {
55	                $migration = new $className($db);
56	                $migration->up();
57	            }
58	        }
59	    }
60	}
