5	namespace VeloCMS\Core\Services;
6	
7	class TranslationService
8	{
9	    public function translate(string $text, string $from = 'DE', string $to = 'EN'): string
10	    {
11	        try {
12	            return $this->translateWithDeepL($text, $from, $to);
13	        } catch (\Exception $e) {
14	            error_log('DeepL translation failed: ' . $e->getMessage());
15	        }
16	
17	        return $this->translateWithAnthropic($text, $from, $to);
18	    }
19	
20	    private function translateWithDeepL(string $text, string $from, string $to): string
21	    {
22	        $key = $_ENV['DEEPL_KEY'] ?? '';
23	
24	        if (empty($key)) {
25	            throw new \RuntimeException('No DeepL API key configured');
26	        }
27	
28	        $response = $this->httpPost(
29	            'https://api-free.deepl.com/v2/translate',
30	            http_build_query([
31	                'auth_key'    => $key,
32	                'text'        => $text,
33	                'source_lang' => $from,
34	                'target_lang' => $to,
35	            ]),
36	            ['Content-Type: application/x-www-form-urlencoded']
37	        );
38	
39	        $data = json_decode($response, true);
40	
41	        if (!isset($data['translations'][0]['text'])) {
42	            throw new \RuntimeException('Invalid DeepL response: ' . $response);
43	        }
44	
45	        return $data['translations'][0]['text'];
46	    }
47	
48	    private function translateWithAnthropic(string $text, string $from, string $to): string
49	    {
50	        $key = $_ENV['ANTHROPIC_KEY'] ?? '';
51	
52	        if (empty($key)) {
53	            throw new \RuntimeException('No Anthropic API key configured');
54	        }
55	
56	        $payload = json_encode([
57	            'model'      => 'claude-haiku-4-5-20251001',
58	            'max_tokens' => 1024,
59	            'messages'   => [[
60	                'role'    => 'user',
61	                'content' => "Translate the following text from {$from} to {$to}. "
62	                           . "Return only the translation, nothing else:\n\n{$text}",
63	            ]],
64	        ]);
65	
66	        $response = $this->httpPost(
67	            'https://api.anthropic.com/v1/messages',
68	            $payload,
69	            [
70	                'x-api-key: '          . $key,
71	                'anthropic-version: 2023-06-01',
72	                'content-type: application/json',
73	            ]
74	        );
75	
76	        $data = json_decode($response, true);
77	
78	        if (!isset($data['content'][0]['text'])) {
79	            throw new \RuntimeException('Invalid Anthropic response: ' . $response);
80	        }
81	
82	        return $data['content'][0]['text'];
83	    }
84	
85	    private function httpPost(string $url, string $body, array $headers = []): string
86	    {
87	        $ch = curl_init($url);
88	
89	        curl_setopt_array($ch, [
90	            CURLOPT_POST           => true,
91	            CURLOPT_POSTFIELDS     => $body,
92	            CURLOPT_RETURNTRANSFER => true,
93	            CURLOPT_HTTPHEADER     => $headers,
94	            CURLOPT_TIMEOUT        => 15,
95	            CURLOPT_SSL_VERIFYPEER => true,
96	        ]);
97	
98	        $response = curl_exec($ch);
99	        $error    = curl_error($ch);
100	        curl_close($ch);
101	
102	        if ($response === false) {
103	            throw new \RuntimeException("HTTP request failed: {$error}");
104	        }
105	
106	        return (string) $response;
107	    }
108	}
