# veloCMS — Architecture Guard

**Ziel:** Claude Code muss folgende bewährte Muster WIEDERHOLEN, nicht experimentieren.

Dieses Dokument ist die **Wahrheit** für veloCMS-Entwicklung. Abweichungen führen zu Crashes.

---

## ✅ BEWÄHRTE PATTERN (Diese funktionieren)

### Module-Struktur

Jedes Modul folgt diesem Aufbau:

```
velocms/modules/[ModuleName]/
├── [ModuleName]Module.php         (Modul-Bootstrapper)
├── Controllers/
│   ├── Admin[ModuleName]Controller.php
│   └── [ModuleName]Controller.php   (Frontend, falls benötigt)
├── Models/
│   └── [ModuleName]Model.php
├── migrations/
│   ├── 001_create_[table]_table.php
│   └── 002_...php
└── views/
    ├── admin/
    │   ├── index.php
    │   └── edit.php
    └── frontend/
        └── index.php
```

### Module-Klasse (Base Pattern)

```php
<?php
declare(strict_types=1);

namespace VeloCMS\Modules\[ModuleName];

use VeloCMS\Core\Module;

class [ModuleName]Module extends Module
{
    public string $name    = '[ModuleName]';
    public string $version = '1.0.0';

    public function boot(): void
    {
        // Admin routes
        $this->router->get('/admin/[slug]',              '[ModuleName]\Controllers\Admin[ModuleName]Controller@index');
        $this->router->get('/admin/[slug]/new',          '[ModuleName]\Controllers\Admin[ModuleName]Controller@new');
        $this->router->post('/admin/[slug]/save',        '[ModuleName]\Controllers\Admin[ModuleName]Controller@save');
        $this->router->get('/admin/[slug]/edit/[i:id]',  '[ModuleName]\Controllers\Admin[ModuleName]Controller@edit');
        $this->router->post('/admin/[slug]/update/[i:id]','[ModuleName]\Controllers\Admin[ModuleName]Controller@update');
        $this->router->post('/admin/[slug]/delete/[i:id]','[ModuleName]\Controllers\Admin[ModuleName]Controller@delete');

        // Frontend routes (wenn benötigt)
        $this->router->get('/[slug]',          '[ModuleName]\Controllers\[ModuleName]Controller@index');
        $this->router->get('/[slug]/[a:slug]', '[ModuleName]\Controllers\[ModuleName]Controller@show');

        // Admin menu
        $this->admin->addMenuItem([
            'label'    => t('nav.[slug]'),
            'url'      => '/admin/[slug]',
            'icon'     => '[icon]',
            'position' => 30,
        ]);
    }

    public function install(): void
    {
        $this->runMigrations(__DIR__ . '/migrations');
    }
}
```

**REGEL:** Alle Module folgen diesem Pattern. Keine Abweichungen.

### Controller-Klasse (Base Pattern)

```php
<?php
declare(strict_types=1);

namespace VeloCMS\Modules\[ModuleName]\Controllers;

use VeloCMS\Core\Auth;
use VeloCMS\Core\Controller;
use VeloCMS\Modules\[ModuleName]\Models\[ModuleName]Model;

class Admin[ModuleName]Controller extends Controller
{
    private [ModuleName]Model $model;

    public function __construct()
    {
        parent::__construct();
        $this->requireAuth();
        $this->model = new [ModuleName]Model();
    }

    public function index(): void
    {
        $this->view->extend('admin');
        $this->render('admin/index', ['items' => $this->model->getAll()]);
