-- Migration: Add Grid Positioning Columns to velocms_boxes
-- Created: 2026-05-26
-- Purpose: Support Gridstack.js 24-column grid positioning for Visual Editor

ALTER TABLE velocms_boxes ADD COLUMN (
    grid_x INT UNSIGNED DEFAULT 0 COMMENT 'Grid column position (0-24)',
    grid_y INT UNSIGNED DEFAULT 0 COMMENT 'Grid row position',
    grid_w INT UNSIGNED DEFAULT 8 COMMENT 'Grid width in columns (1-24)',
    grid_h INT UNSIGNED DEFAULT 3 COMMENT 'Grid height in rows'
);

-- Add index for faster lookups by page + grid position
ALTER TABLE velocms_boxes ADD INDEX idx_page_grid_position (page_id, grid_x, grid_y);

-- Optional: Add constraints to ensure valid grid values
ALTER TABLE velocms_boxes ADD CONSTRAINT check_grid_width
    CHECK (grid_w >= 1 AND grid_w <= 24);

ALTER TABLE velocms_boxes ADD CONSTRAINT check_grid_height
    CHECK (grid_h >= 1);

